window.__QUIZ_DATA__=[{"id":"theory>Geography>2014>Theory 1>1>a","subject":"Geography","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Highlight any five factors that have accounted for the world's rapid population growth.","images":[],"marking_scheme":"- Early marriages   - Poor family planning   - Improved Hygiene   - Low mortality rate   - Polygamy","marks":"10","difficulty":"2"},{"id":"theory>Geography>2014>Theory 1>1>b","subject":"Geography","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Outline any five problems of rapid population growth.","images":[],"marking_scheme":"- Increase crime rate   - Waste management problems   - Easy spread of diseases   - Pressure on social amenities   - Inadequate housing","marks":"10","difficulty":"2"},{"id":"theory>Geography>2014>Theory 1>2>a>i","subject":"Geography","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Describe four classes of towns based on their functions","images":[],"marking_scheme":"-  Resort towns:  These are places of interest where people can visit for recreation.   -  Satellite towns:  These are towns which have well-planned centres  -  Commercial towns:  They are centres of commercial or financial activities where trade is the primary activity  -  Royal towns:  These are towns which have traditional centres for monarchs.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2014>Theory 1>2>a>ii","subject":"Geography","year":"2014","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Describe four classes of towns based on their functionsGive one example of each of the classes of towns described in 2(a) (i) above.","images":[],"marking_scheme":"- Resort towns E.g Miami   - Satellite towns E.g Norwich   - Commercial towns E.g London   - Royal towns E.g. Ife","marks":"7","difficulty":"3"},{"id":"theory>Geography>2014>Theory 1>2>b","subject":"Geography","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Explain four ways in which rural and urban areas are interdependent.","images":[],"marking_scheme":"- Rural areas provide unskilled labour to urban centres   - Rural areas are custodians of culture and traditions to urban areas   - Urban centres provide recreational facilities for rural areas.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2014>Theory 1>3>a","subject":"Geography","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Highlight five characteristics of manufacturing industries in Tropical African countries.","images":[],"marking_scheme":"- They are labour-intensive   - They import some raw materials   - They depend on imported machines & foreign technology   - They are mainly small-scale   - They produce consumer goods.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2014>Theory 1>3>b","subject":"Geography","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline five problems of manufacturing industries in your country","images":[],"marking_scheme":"- Shortage of raw materials   - Low purchasing power of consumers   - Poor quality of industrial labour   - Restriction of foreign exchange  - Inadequate power supply","marks":"10","difficulty":"2"},{"id":"theory>Geography>2014>Theory 1>4>a>i","subject":"Geography","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : NIGERIA ON BROAD OUTLINE","question":"Describe Nigeria under the following headings:    - location;","images":[],"marking_scheme":"- It is located between lat. 40N and 140N, and also between 30E and 150E. It is located in Africa at the centre of the curve made at the western part of the continent i.e West Africa. It is bordered in the North by Niger Republic, in the North-East by Chad Republic in the West by Benin Republic, in the east by Republic of Cameroon, in the south by the Atlantic ocean.","marks":"8","difficulty":"1"},{"id":"theory>Geography>2014>Theory 1>4>a>ii","subject":"Geography","year":"2014","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : NIGERIA ON BROAD OUTLINE","question":"Describe Nigeria under the following headings:size.","images":[],"marking_scheme":"It is the fourth largest country in West Africa by land mass and has a total area of 923,768sq.km. It stretches for about 1,300km east to west and for about 1,100km North to South.","marks":"7","difficulty":"1"},{"id":"theory>Geography>2014>Theory 1>4>b","subject":"Geography","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"In what five ways are highlands important to the economy of Nigeria?","images":[],"marking_scheme":"- Source of minerals   - Climatic barrier   - Source of construction materials   - For the practice of specialized agriculture   - Moderation of climate","marks":"5","difficulty":"2"},{"id":"theory>Geography>2014>Theory 1>5>a","subject":"Geography","year":"2014","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw an outline map of Nigeria. On the map, show and name: (i) the Western Highlands;   (ii) Rivers Niger and Benue; (iii) The Kainji Lake; (iv) Lagos.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2014>Theory 1>5>b","subject":"Geography","year":"2014","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Highlight any three characteristics of rivers in Nigeria.","images":[],"marking_scheme":"- Presence of debris   - Seasonal fluctuation in volume   - Shallowness of rivers","marks":"10","difficulty":"2"},{"id":"theory>Geography>2014>Theory 1>6>a","subject":"Geography","year":"2014","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria. On the map, show and name: (i) the Western Highlands;   (ii) Rivers Niger and Benue; (iii) the Kainji Lake to Nigeria.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"15","difficulty":"3"},{"id":"theory>Geography>2014>Theory 1>6>b","subject":"Geography","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Explain for factors which encourage cattle rearing in Northern Nigeria.","images":[],"marking_scheme":"- Availability of pasture for cattle grazing   - Availability of large cattle markets   - Availability of transport network   - Availability of traditional cattle rearers","marks":"3","difficulty":"2"},{"id":"theory>Geography>2014>Theory 1>6>c","subject":"Geography","year":"2014","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Highlight three reasons why cattle rearing is less important in Southern Nigeria.","images":[],"marking_scheme":"- Limited pasture   - Conflicts sometimes occur with farmers (crop cultivators)  - Comparative cost advantage about cattle rearing","marks":"2","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>1>a","subject":"Geography","year":"2014","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1:50,000 and answer questions that follow.    Draw the outline of the area enclosed by ABCD to a new scale of 1:25,000.","images":[],"marking_scheme":"Given; scale = 1:50,000   Length = 16cm   Breadth = 16cm   New scale = 1:25,000","marks":"5","difficulty":"3"},{"id":"theory>Geography>2014>Theory 2>1>b","subject":"Geography","year":"2014","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1:50,000 and answer questions that follow.  In your new outline, insert and name: (i) River Owan and indicate its direction of flow with an arrow;   (ii) the 250 ft contour line; (iii) SABONGIDA built-up area.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2014>Theory 2>1>c","subject":"Geography","year":"2014","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"Using evidence from the map, identify any two likely occupations of the people who live in the area enclosed by ABCD","images":[],"marking_scheme":"- Fishing   - Trading","marks":"2","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>1>d","subject":"Geography","year":"2014","type":"Theory","sub_label":"d","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Using the entire map extract, state with the evidence any four land use types on the mapped area.","images":[],"marking_scheme":"(i) Transportational land as evidenced by presence of roads   (ii) Commercial land use as shown by the presence of markets   (iii) Trading due to the presence of markets  (iv) Farming due to the presence of scattered cultivation.","marks":"1","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>2>a","subject":"Geography","year":"2014","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Use the data in the table below to answer the questions that follow.Production of cocoa in country Z (in thousand tonnes) for 2008 and 2009 from three production regions A, B and C.   Region Year YearRegion 2008 2009 A 30 40 B 40 30 C 50 70    Construct a multiple bar graph to show the data.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"15","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>2>b","subject":"Geography","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Production of cocoa in country Z (in thousand tonnes) for 2008 and 2009 from three production regions A, B and C.   Region Year YearRegion 2008 2009 A 30 40 B 40 30 C 50 70  Outline any three advantages of the method used.","images":[],"marking_scheme":"- It is easy to understand and construct   - It is attractive and eyecatching   - It makes comparison easy","marks":"5","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>3>a","subject":"Geography","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"What is latitude?","images":[],"marking_scheme":"Latitude is an imaginary line running from East to West on the earth surface.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2014>Theory 2>3>b","subject":"Geography","year":"2014","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"State any three similarities between lines of longitude and latitudes","images":[],"marking_scheme":"- Both lines are imaginary lines   - Both lines are used to locate places   - Both lines contain great circles.","marks":"7","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>3>c","subject":"Geography","year":"2014","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Outline any five ways in which lines of longitudes differ from lines of latitudes.","images":[],"marking_scheme":"Longitudes Latitudes(i) They run from North to South They run from East to West(ii) They are used to calculate time They are used to calculate distance(iii) They are known as meridians They are known as parallels (iv) It is a semicircle of 1800 It is a complete circle of 3600 (v) All opposite longitudes form great circles The only latitude which forms great circles is the Equator","marks":"8","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>4>a","subject":"Geography","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Define climate","images":[],"marking_scheme":"Climate is the average weather condition of a place taken over a long period of time usually between 30 - 40 years.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2014>Theory 2>4>b","subject":"Geography","year":"2014","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"With the aid of a diagram, describe how latitudes influence temperature.","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"Influence of Latitude on Temperature   Temperature decreases from the equatorial region to the poles - Band of rays from the sun fall vertically over the equatorial regions. This band travels through a very short distance at the same time and heats up a smaller surface area. Later the rays in the temperate latitude heat up a larger area than that of the tropics, thereby resulting in lower temperatures.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>4>c","subject":"Geography","year":"2014","type":"Theory","sub_label":"c","group":"FINAL","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Calculate the temperature at a coastal mountain peak of height 6000 metres when the temperature at sea level is 40oC.","images":[],"marking_scheme":"Calculation of Temperature lapse   rate: 0.65 for every 100m of ascent 6.5 for every 1000m of ascent   \u2234 6000m will have a lapse rate of;   (6.5x60001000)0C=390C    Recall, Temp. at sea level = 400C     \u2234 Temp. at height 6000m will be (40 - 39)0C =10C","marks":"5","difficulty":"3"},{"id":"theory>Geography>2014>Theory 2>5>a","subject":"Geography","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Describe chemically formed sedimentary rocks under the following headings:    mode of formation;","images":[],"marking_scheme":"They are formed from streams, winds, and glaciers, etc. The accumulation of materials are derived from other rocks over a long period of time. After some time, the cemented precipitate rock hardens and is layered.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>5>b","subject":"Geography","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Describe chemically formed sedimentary rocks under the following headings:examples","images":[],"marking_scheme":"Examples:  Alabasta, Potash, Borax, Flint, Dolomite, Limonite, etc.","marks":"7","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>5>c","subject":"Geography","year":"2014","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"importance.","images":[],"marking_scheme":"- They are medical   - They serve as tourist attractions   - For construction and building   - For ornamental uses, etc.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2014>Theory 2>6>a","subject":"Geography","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Explain the occurrence of drought under the following headings:    cause;","images":[],"marking_scheme":"- Presence of high daily temperature   - Climate change   - Presence of green house gases   - Prolonged rainfall   - Deforestation","marks":"8","difficulty":"3"},{"id":"theory>Geography>2014>Theory 2>6>b","subject":"Geography","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"area affected;","images":[],"marking_scheme":"- Northen Nigeria   - Niger Republic   - Mauritania   - Ethiopia   - Burkina Faso","marks":"7","difficulty":"1"},{"id":"theory>Geography>2014>Theory 2>6>c","subject":"Geography","year":"2014","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"area affected; control","images":[],"marking_scheme":"- Death of animals   - Loss of crops   - Starvation   - Control grazing   - Irrigation projects","marks":"5","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>7>a","subject":"Geography","year":"2014","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"List three processes of river erosion.","images":[],"marking_scheme":"- Hydraulic action   - Attrition   - Corrassion","marks":"10","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>7>b>i","subject":"Geography","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Outline four characteristics of each of the following section of a river valley:    - upper course; (ii) middle course; (iii) lower course.","images":[],"marking_scheme":"- It marks the river beginning   - It has steep slopes   - It occurs in highlands   - Its valleys are V-shaped","marks":"5","difficulty":"3"},{"id":"theory>Geography>2014>Theory 2>7>b>ii","subject":"Geography","year":"2014","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Outline four characteristics of each of the following section of a river valley:-  middle course;","images":[],"marking_scheme":"Meanders are typical landforms found in this stage of the river. A meander is a winding curve or bend in a river. They are typical of the middle and lower course of a river. This is because vertical erosion is replaced by a sideways form of erosion called LATERAL erosion, plus deposition within the floodplain.","marks":"3","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>7>b>iii","subject":"Geography","year":"2014","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Outline four characteristics of each of the following section of a river valley:- Lower course;","images":[],"marking_scheme":"There is a wide, flat flood plain either side of the river. There are features such as meanders, ox bow lakes and deltas. The flood plain is made up of a thick layer of alluvium.","marks":"2","difficulty":"2"},{"id":"theory>Geography>2014>Theory 2>8>a","subject":"Geography","year":"2014","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"List three processes of river erosion.","images":["data:image/png;base64,"],"marking_scheme":"Water Table   When rain falls, some of the water evaporate, some run off while some sink into the ground. The downward movement by the force of gravity continues until an impermeable layer is reached. The water accumulates above the impermeable layer and saturates the rock. The permeable rock in which the water is tored is called an 'acquifer'.","marks":"15","difficulty":"1"},{"id":"theory>Geography>2014>Theory 2>8>b","subject":"Geography","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Outline three factors that influence the depth of water table.","images":[],"marking_scheme":"- Presence of boreholes and wells   - High and low tides   - Types of rocks","marks":"5","difficulty":"1"}];